// BACKEND API CONFIG
// Change this to your deployed backend URL when going live.
// For local dev: http://localhost:5000/api
// For Render/Railway: https://your-backend.onrender.com/api
// ─────────────────────────────────────────────────────────────────────────────
const API_BASE = "https://suchitra-backend.onrender.com/api";

// ─── SECURE TOKEN STORAGE (sessionStorage — clears on tab close) ──────────────
const TOKEN_KEY = "sfs_token";
const getToken  = () => { try { return sessionStorage.getItem(TOKEN_KEY); } catch { return null; } };
const saveToken = (t) => { try { sessionStorage.setItem(TOKEN_KEY, t); } catch {} };
const clearToken= () => { try { sessionStorage.removeItem(TOKEN_KEY); } catch {} };

// ─── API LAYER ────────────────────────────────────────────────────────────────
async function apiFetch(path, opts = {}) {
  const token = getToken();
  const headers = { "Content-Type": "application/json", ...(opts.headers || {}) };
  if (token) headers["Authorization"] = `Bearer ${token}`;
  let res, data;
  try {
    res  = await fetch(`${API_BASE}${path}`, { ...opts, headers });
    data = await res.json();
  } catch {
    throw new Error("Cannot reach server. Is the backend running?");
  }
  if (!res.ok) throw new Error(data?.message || `Error ${res.status}`);
  return data;
}

const API = {
  // Public
  submitLead:  (b) => apiFetch("/leads/submit",  { method:"POST", body:JSON.stringify(b) }),
  health:      ()  => apiFetch("/health"),
  // Auth
  login: async (email, password) => {
    const d = await apiFetch("/auth/login", { method:"POST", body:JSON.stringify({ email, password }) });
    if (d.token) saveToken(d.token);
    return d;
  },
  logout:         ()       => clearToken(),
  getMe:          ()       => apiFetch("/auth/me"),
  changePassword: (cp, np) => apiFetch("/auth/change-password", { method:"PUT", body:JSON.stringify({ currentPassword:cp, newPassword:np }) }),
  seedAdmin:      ()       => apiFetch("/auth/seed", { method:"POST" }),
  // Leads
  getLeads:     (p={}) => apiFetch("/leads?" + new URLSearchParams(p)),
  getStats:     ()     => apiFetch("/leads/stats"),
  updateStatus: (id,s) => apiFetch(`/leads/${id}/status`, { method:"PATCH", body:JSON.stringify({ status:s }) }),
  updateLead:   (id,b) => apiFetch(`/leads/${id}`,        { method:"PATCH", body:JSON.stringify(b) }),
  deleteLead:   (id)   => apiFetch(`/leads/${id}`,        { method:"DELETE" }),
  exportCSV:    ()     => { window.open(`${API_BASE}/leads/export/csv?token=${getToken()}`, "_blank"); },
};

