// ─── TOAST ────────────────────────────────────────────────────────────────────
function Toast({ msg, type, onClose }) {
  useEffect(() => { const t = setTimeout(onClose, 4000); return () => clearTimeout(t); }, [onClose]);
  const bg = type==="error"?C.danger : type==="warn"?C.warn : C.success;
  return (
    <div style={{ position:"fixed", top:20, right:20, zIndex:9999, background:bg, color:C.white, borderRadius:10, padding:"14px 20px", fontWeight:700, fontSize:14, boxShadow:"0 4px 20px rgba(0,0,0,0.25)", maxWidth:360, display:"flex", gap:12, alignItems:"center" }}>
      <span style={{ flex:1 }}>{msg}</span>
      <button onClick={onClose} style={{ background:"none", border:"none", color:C.white, cursor:"pointer", fontSize:20, lineHeight:1 }}>×</button>
    </div>
  );
}

