// ─── STAT COUNTER ─────────────────────────────────────────────────────────────
function StatCard({ value, label }) {
  const [c, setC] = useState(0);
  const num = parseInt(value.replace(/[^0-9]/g,""));
  useEffect(() => {
    let s=0; const step=Math.ceil(num/60);
    const t = setInterval(() => { s+=step; if(s>=num){setC(num);clearInterval(t);}else setC(s); }, 20);
    return () => clearInterval(t);
  }, [num]);
  const suffix = value.includes("+") ? "+" : value.includes("%") ? "%" : value.includes("Cr") ? " Cr" : "";
  return (
    <div style={{ textAlign:"center", background:"rgba(255,255,255,0.08)", borderRadius:14, padding:"22px 16px", border:"1px solid rgba(255,255,255,0.15)" }}>
      <div style={{ fontSize:34, fontWeight:900, color:C.goldLight, fontFamily:"'Playfair Display',Georgia,serif" }}>{c}{suffix}</div>
      <div style={{ color:"#B0C4DE", fontSize:13, marginTop:5 }}>{label}</div>
    </div>
  );
}

