// ─── EMI CALCULATOR ───────────────────────────────────────────────────────────
function EMIPage() {
  const [amount, setAmount] = useState(2500000);
  const [rate,   setRate]   = useState(8.5);
  const [tenure, setTenure] = useState(240);
  const emi      = calcEMI(amount,rate,tenure);
  const total    = emi*tenure;
  const interest = total-amount;
  const pPct     = Math.round((amount/total)*100);
  return (
    <div>
      <div style={{ background:C.navy, padding:"58px 24px", textAlign:"center" }}>
        <div style={{ color:C.goldLight, fontSize:12, fontWeight:700, letterSpacing:2, textTransform:"uppercase", marginBottom:10 }}>TOOLS</div>
        <h1 style={{ color:C.white, fontSize:42, fontWeight:900, fontFamily:"'Playfair Display',Georgia,serif", margin:0 }}>EMI Calculator</h1>
      </div>
      <div style={{ maxWidth:880, margin:"0 auto", padding:"58px 24px" }}>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:30 }}>
          <div style={card}>
            <h3 style={{ color:C.navy, fontSize:18, fontWeight:800, fontFamily:"'Playfair Display',Georgia,serif", margin:"0 0 26px" }}>Loan Details</h3>
            {[
              { lb:"Loan Amount",       min:100000,  max:10000000, step:50000, val:amount, set:setAmount, unit:"₹"+(amount/100000).toFixed(1)+" Lakhs" },
              { lb:"Interest Rate p.a.",min:6,       max:20,       step:0.1,   val:rate,   set:setRate,   unit:rate+"%" },
              { lb:"Loan Tenure",       min:12,      max:360,      step:12,    val:tenure, set:setTenure, unit:Math.round(tenure/12)+" Yrs ("+tenure+" mo)" },
            ].map((item,i)=>(
              <div key={i} style={{ marginBottom:26 }}>
                <div style={{ display:"flex", justifyContent:"space-between", marginBottom:7 }}>
                  <label style={{ ...label, margin:0 }}>{item.lb}</label>
                  <span style={{ background:C.navy, color:C.white, borderRadius:7, padding:"3px 12px", fontSize:12, fontWeight:700 }}>{item.unit}</span>
                </div>
                <input type="range" min={item.min} max={item.max} step={item.step} value={item.val} onChange={e=>item.set(parseFloat(e.target.value))} style={{ width:"100%", accentColor:C.gold }}/>
              </div>
            ))}
          </div>
          <div>
            <div style={{ ...card, background:C.navy, marginBottom:18 }}>
              <div style={{ color:"#9DB8D8", fontSize:13, fontWeight:600 }}>Monthly EMI</div>
              <div style={{ color:C.goldLight, fontSize:42, fontWeight:900, fontFamily:"'Playfair Display',Georgia,serif", margin:"7px 0" }}>{fmt(emi)}</div>
              <div style={{ color:"#6B85A0", fontSize:12 }}>per month</div>
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:14, marginBottom:18 }}>
              {[["Principal",fmt(amount),C.blue],["Total Interest",fmt(interest),C.gold],["Total Payment",fmt(total),C.navy],["Interest %",(100-pPct)+"% of total",C.mid]].map(([lb,val,col])=>(
                <div key={lb} style={{ background:C.offWhite, borderRadius:11, padding:14, border:`1.5px solid ${C.border}` }}>
                  <div style={{ color:C.light, fontSize:11, fontWeight:700, textTransform:"uppercase", letterSpacing:0.5, marginBottom:5 }}>{lb}</div>
                  <div style={{ color:col, fontSize:17, fontWeight:800 }}>{val}</div>
                </div>
              ))}
            </div>
            <div style={card}>
              <h4 style={{ margin:"0 0 14px", color:C.navy, fontSize:14, fontWeight:700 }}>Payment Breakdown</h4>
              <div style={{ background:C.border, borderRadius:7, height:18, overflow:"hidden", marginBottom:10 }}>
                <div style={{ height:"100%", width:pPct+"%", background:C.blue, display:"inline-block", transition:"width 0.5s" }}/>
                <div style={{ height:"100%", width:(100-pPct)+"%", background:C.gold, display:"inline-block", transition:"width 0.5s" }}/>
              </div>
              <div style={{ display:"flex", gap:18 }}>
                {[["Principal",pPct,C.blue],["Interest",100-pPct,C.gold]].map(([lb,pct,col])=>(
                  <div key={lb} style={{ display:"flex", alignItems:"center", gap:7 }}>
                    <div style={{ width:11, height:11, background:col, borderRadius:3 }}/>
                    <span style={{ fontSize:12, color:C.mid }}>{lb} ({pct}%)</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── ELIGIBILITY ──────────────────────────────────────────────────────────────
function EligibilityPage() {
  const [form, setForm] = useState({ income:75000, obligations:15000, occupation:"salaried", loanType:"home" });
  const [result, setResult] = useState(null);
  const check = () => {
    const maxEMI = (form.income-form.obligations)*0.5;
    const r = { home:8.5, business:12, personal:14, mortgage:10 }[form.loanType]/12/100;
    const n = { home:240, business:60, personal:60, mortgage:120 }[form.loanType];
    const eligible = maxEMI*((Math.pow(1+r,n)-1)/(r*Math.pow(1+r,n)));
    const mult = { salaried:1, "self-employed":0.85, business:1.1 }[form.occupation]||1;
    setResult(Math.round(eligible*mult/100000)*100000);
  };
  return (
    <div>
      <div style={{ background:C.navy, padding:"58px 24px", textAlign:"center" }}>
        <div style={{ color:C.goldLight, fontSize:12, fontWeight:700, letterSpacing:2, textTransform:"uppercase", marginBottom:10 }}>TOOLS</div>
        <h1 style={{ color:C.white, fontSize:42, fontWeight:900, fontFamily:"'Playfair Display',Georgia,serif", margin:0 }}>Loan Eligibility Checker</h1>
      </div>
      <div style={{ maxWidth:680, margin:"0 auto", padding:"58px 24px" }}>
        <div style={card}>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:18, marginBottom:22 }}>
            <div><label style={label}>Monthly Income (₹)</label><input type="number" value={form.income} onChange={e=>setForm(p=>({...p,income:+e.target.value}))} style={input}/></div>
            <div><label style={label}>Existing EMI Obligations (₹)</label><input type="number" value={form.obligations} onChange={e=>setForm(p=>({...p,obligations:+e.target.value}))} style={input}/></div>
            <div><label style={label}>Occupation</label><select value={form.occupation} onChange={e=>setForm(p=>({...p,occupation:e.target.value}))} style={input}><option value="salaried">Salaried</option><option value="self-employed">Self-Employed</option><option value="business">Business Owner</option></select></div>
            <div><label style={label}>Loan Type</label><select value={form.loanType} onChange={e=>setForm(p=>({...p,loanType:e.target.value}))} style={input}><option value="home">Home Loan</option><option value="business">Business Loan</option><option value="personal">Personal Loan</option><option value="mortgage">Mortgage Loan</option></select></div>
          </div>
          <button onClick={check} style={{ ...btn.gold, width:"100%", padding:15, fontSize:15 }}>Check My Eligibility →</button>
          {result && (
            <div style={{ marginTop:30, textAlign:"center", background:`linear-gradient(135deg,${C.navy},#1B3A6A)`, borderRadius:14, padding:36 }}>
              <div style={{ color:"#9DB8D8", fontSize:14, marginBottom:10 }}>You may be eligible for up to</div>
              <div style={{ color:C.goldLight, fontSize:48, fontWeight:900, fontFamily:"'Playfair Display',Georgia,serif", marginBottom:7 }}>
                {result>=10000000 ? "₹"+(result/10000000).toFixed(2)+" Cr" : "₹"+(result/100000).toFixed(0)+" L"}
              </div>
              <div style={{ color:"#6B85A0", fontSize:12, marginTop:18 }}>*Estimate only. Final eligibility determined by lender.</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

