// ─── ADMIN — Change Password Modal ────────────────────────────────────────────
function ChangePasswordModal({ onClose, showToast }) {
  const [f, setF]     = useState({ current:"", newPw:"", confirm:"" });
  const [loading, setLoading] = useState(false);
  const submit = async (e) => {
    e.preventDefault();
    if(f.newPw!==f.confirm){ showToast("New passwords do not match","error"); return; }
    if(f.newPw.length<8){ showToast("Password must be at least 8 characters","error"); return; }
    setLoading(true);
    try {
      await API.changePassword(f.current, f.newPw);
      showToast("Password changed! Please log in again.","success");
      API.logout();
      setTimeout(()=>window.location.reload(), 2200);
    } catch(err){ showToast(err.message||"Failed to change password","error"); }
    finally{ setLoading(false); }
  };
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.65)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:2000 }}>
      <div style={{ ...card, maxWidth:400, width:"100%", position:"relative" }}>
        <button onClick={onClose} style={{ position:"absolute", top:14, right:14, background:"none", border:"none", fontSize:22, cursor:"pointer", color:C.light }}>×</button>
        <h2 style={{ color:C.navy, fontSize:20, fontWeight:800, fontFamily:"'Playfair Display',Georgia,serif", margin:"0 0 5px" }}>Change Admin Password</h2>
        <p style={{ color:C.light, fontSize:12, margin:"0 0 22px" }}>Use a strong password of at least 8 characters. It will never be shown to anyone.</p>
        <form onSubmit={submit} style={{ display:"flex", flexDirection:"column", gap:14 }}>
          <div><label style={label}>Current Password</label><input type="password" required style={input} placeholder="••••••••" value={f.current} onChange={e=>setF(p=>({...p,current:e.target.value}))}/></div>
          <div><label style={label}>New Password (min 8 chars)</label><input type="password" required style={input} placeholder="••••••••" value={f.newPw} onChange={e=>setF(p=>({...p,newPw:e.target.value}))}/></div>
          <div><label style={label}>Confirm New Password</label><input type="password" required style={input} placeholder="••••••••" value={f.confirm} onChange={e=>setF(p=>({...p,confirm:e.target.value}))}/></div>
          <button type="submit" disabled={loading} style={{ ...btn.gold, padding:13, width:"100%", opacity:loading?0.7:1 }}>{loading?"Changing…":"Save New Password"}</button>
        </form>
      </div>
    </div>
  );
}

